+        PMsg::Sequence(vec!["s1".into(), "s2".into()]),
+        PMsg::Step("final".into()),
+    ]);
+
+    assert_eq!(
+        trace,
+        vec![
+            "init",
+            "update:init",
+            "batch:2",
+            "step:b1",
+            "step:b2",
+            "seq:2",
+            "step:s1",
+            "step:s2",
+            "step:final",
+            "on_shutdown",
+        ]
+    );
+}
