+
+    let quit_pos = trace.iter().position(|s| s == "quit").unwrap();
+    let shutdown_pos = trace.iter().position(|s| s == "on_shutdown").unwrap();
+    assert!(
+        shutdown_pos > quit_pos,
+        "on_shutdown must run after quit"
+    );
+}
